mapper.sql:
SELECT A.CRT_YM , A.CONTRACT_NUM , A.SVC_CNTR_NO , A.SUBSCRIBER_NO , A.SUBSCRIBER_NO AS SUBSCRIBER_NO_MASK , A.OPEN_DT , C.SUB_STATUS , FN_GET_CODENM('MSP0003', C.SUB_STATUS) AS SUB_STATUS_NM , D.CUSTOMER_LINK_NAME AS CUST_NM , D.CUSTOMER_LINK_NAME AS CUST_NM_MASK , D.CUSTOMER_TYPE AS CUST_TP , FN_GET_CODENM('MSP0009', D.CUSTOMER_TYPE) AS CUST_TP_NM , A.OPEN_AGNT_CD , FN_GET_ORGNM(A.OPEN_AGNT_CD) AS OPEN_AGNT_NM , ( SELECT PRDT_CODE FROM CMN_INTM_MDL WHERE RPRS_PRDT_ID = A.MODEL_ID AND RPRS_YN = 'Y' ) AS PRDT_CODE , A.OUT_AMNT , B.INST_AMNT , A.INST_MNTH_CNT , CASE WHEN ADD_MONTHS(TO_DATE(SUBSTR(A.GRNT_INSR_MNGM_NO, 1, 8), 'YYYYMMDD'), A.INST_MNTH_CNT) <= SYSDATE THEN 0 ELSE TRUNC(MONTHS_BETWEEN(ADD_MONTHS(TO_DATE(SUBSTR(A.GRNT_INSR_MNGM_NO, 1, 8), 'YYYYMMDD'), A.INST_MNTH_CNT), SYSDATE)) END AS REMAIN_CNT , A.GRNT_INSR_MNGM_NO , A.AGRM_MNTH_CNT , CASE WHEN ADD_MONTHS(TO_DATE(A.OPEN_DT, 'YYYYMMDD'), A.AGRM_MNTH_CNT) <= SYSDATE THEN 0 ELSE TRUNC(MONTHS_BETWEEN(ADD_MONTHS(TO_DATE(A.OPEN_DT, 'YYYYMMDD'), A.AGRM_MNTH_CNT), SYSDATE)) END AS REMAIN_AGRM_CNT , FN_GET_CODENM('MSP0007', C.UNPD_IND_CD) AS UNPD_YN , A.CLAUSE_PRI_AD_FLAG AS MKT_AGRM_YN , A.VOC_PRSN_ID , FN_GET_USRNM(A.VOC_PRSN_ID) AS VOC_PRSN_NM , A.TM_STAT_CD , FN_GET_CODENM('RCP0066', A.TM_STAT_CD) AS TM_STAT_NM , A.TM_RSLT_CD , FN_GET_CODENM('RCP0069', A.TM_RSLT_CD) AS TM_RSLT_NM , A.VOC_RCP_ID , E.CNSL_MID_CD AS DVC_CHG_RSN_CD , SUBSTR(E.CNSL_DTL_CD, 4) AS DVC_CHG_RSN_DTL_CD , A.TM_CNTT FROM MSP_DVC_CHG_TRGT_MST A , MSP_DAILY_CLOSE_STTC B , MSP_JUO_SUB_INFO C , MSP_JUO_CUS_INFO D , MSP_VOC_MGMT_MST E WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.CONTRACT_NUM = C.CONTRACT_NUM AND A.CUSTOMER_ID = D.CUSTOMER_ID AND A.VOC_RCP_ID = E.RCP_ID(+) AND A.CLAUSE_PRI_AD_FLAG = 'Y'
AND A.CRT_YM = #{crtYm}
AND A.OPEN_AGNT_CD = #{openAgntCd}
AND A.TM_STAT_CD = #{tmStatCd}
AND A.TM_RSLT_CD = #{tmRsltCd}
AND D.CUSTOMER_LINK_NAME LIKE '%' || #{srchVal} || '%'
AND (A.CONTRACT_NUM = #{srchVal} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{srchVal}))
AND A.SUBSCRIBER_NO = #{srchVal}
AND A.VOC_PRSN_ID = #{vocPrsnId}
ORDER BY A.OPEN_DT

mapper.select:
/* dvcChgMapper.getDvcChgAsgnTrgtList */


AND A.CLAUSE_PRI_AD_FLAG = 'Y'
AND A.VOC_PRSN_ID IS NULL

mapper.update:
/* dvcChgMapper.updateDvcChgTrgtMst */
UPDATE  MSP_DVC_CHG_TRGT_MST
SET     RVISN_ID = NVL(#{sessionUserId}, #{userId})
        , RVISN_DTTM = SYSDATE

        , VOC_RCP_ID = #{vocRcpId}


        , VOC_PRSN_ID = #{vocPrsnId}


        , TM_STAT_CD = #{tmStatCd}


        , TM_RSLT_CD = #{tmRsltCd}


        , TM_CNTT = #{tmCntt}

WHERE   CRT_YM = #{crtYm}
AND     CONTRACT_NUM = #{contractNum}

mapper.insert:
/* dvcChgMapper.insertVocMgmtDtl */
INSERT INTO MSP_VOC_MGMT_DTL
(
	RCP_ID
	, PROC_DTTM
	, PROC_ORGN_ID
	, PROCR_ID
	, PROC_CNTT
	, REGST_DTTM
)VALUES(
	#{vocRcpId, jdbcType=INTEGER}
	, TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	, #{userOrgnId, jdbcType=VARCHAR}
	, #{userId, jdbcType=VARCHAR}
	, #{tmCntt, jdbcType=VARCHAR}
	, SYSDATE
)

mapper.update:
/* dvcChgMapper.updateVocMgmtMst */
UPDATE  MSP_VOC_MGMT_MST
SET     CNSL_STAT = #{cnslStatCd, jdbcType=VARCHAR}
        , CNSL_MID_CD = #{cnslMidCd, jdbcType=VARCHAR}
        , CNSL_DTL_CD = #{cnslDtlCd, jdbcType=VARCHAR}
        , PROC_ORGN_ID = #{userOrgnId, jdbcType=VARCHAR}
        , PROCR_ID = #{userId, jdbcType=VARCHAR}
        , PROC_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
        , RES_CNTT = #{tmCntt, jdbcType=VARCHAR}

        , CMPL_ORGN_ID = #{userOrgnId, jdbcType=VARCHAR}
        , CMPLR_ID = #{userId, jdbcType=VARCHAR}
        , CMPL_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
        , PROC_MM = ROUND((SYSDATE - TO_DATE(REQ_DTTM, 'YYYYMMDDHH24MISS')) * 24 * 60)

WHERE   RCP_ID = #{vocRcpId, jdbcType=INTEGER}

mapper.select:
/* dvcChgMapper.getAuthCheck */
SELECT  'Y'
FROM    CMN_GRP_CD_MST A
WHERE   A.GRP_ID = 'VOC0017'
AND     A.USG_YN = 'Y'
AND     A.CD_VAL = #{sessionUserId}

mapper.sql:
SELECT A.CONTRACT_NUM , B.SUB_STATUS , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS_NM , B.SUBSCRIBER_NO , B.SUBSCRIBER_NO AS SUBSCRIBER_NO_MASK , B.SUB_LINK_NAME AS CSTMR_NAME , SUBSTR(CRYPTO_AES256.DEC_AES(B.USER_SSN), 1, 6) AS BIRTH_DT , FN_GET_CODENM('RCP9001', C.OPER_TYPE) AS OPER_TYPE_NM , FN_GET_CODENM('RCP9004', C.REQ_BUY_TYPE) AS REQ_BUY_TYPE_NM , FN_GET_CODENM('RCP0007', C.ON_OFF_TYPE) AS ON_OFF_TYPE_NM , CASE WHEN SUBSTR(I.SIM_INFO, 36, 1) IN ('A', 'R') THEN ( SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(I.SIM_INFO, 1, 2)) ELSE (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(I.INST_INFO, 1, 2)) END AS SPRT_TP_NM , TO_CHAR(C.REQ_IN_DAY, 'YYYYMMDDHH24MISS') AS REQ_IN_DAY , TO_CHAR(C.REQ_IN_DAY, 'YYYY-MM-DD HH24:MI:SS') AS REQ_IN_DAY_EX , TO_CHAR(TO_DATE(B.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE , SUBSTR(A.APPL_STRT_DTTM, 1, 8) AS DVC_CHG_DT , TO_CHAR(TO_DATE(SUBSTR(A.APPL_STRT_DTTM, 1, 8), 'YYYYMMDD'), 'YYYY-MM-DD') AS DVC_CHG_DT_EX , DECODE(A.APPL_END_DTTM, '99991231000000', DECODE(B.SUB_STATUS , 'C' ,SUBSTR(SUB_STATUS_DATE , 0 , 8) , '' ), SUBSTR(A.APPL_END_DTTM, 1, 8)) AS DVC_CHG_TMNT_DT , DECODE(A.APPL_END_DTTM, '99991231000000', DECODE(B.SUB_STATUS , 'C' ,TO_CHAR(TO_DATE(SUBSTR(SUB_STATUS_DATE , 0 , 8) , 'YYYYMMDD') , 'YYYY-MM-DD') , '' ), TO_CHAR(TO_DATE(SUBSTR(A.APPL_END_DTTM, 1, 8), 'YYYYMMDD'), 'YYYY-MM-DD')) AS DVC_CHG_TMNT_DT_EX , CASE WHEN A.APPL_END_DTTM = '99991231000000' THEN DECODE(B.SUB_STATUS , 'C' , CASE WHEN TO_DATE(SUBSTR(B.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD') = 0 THEN '당일기변취소' WHEN TO_DATE(SUBSTR(B.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD') < 15 THEN '14일이내해지' WHEN TO_DATE(SUBSTR(B.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD') < 90 THEN '90일이내해지' ELSE '일반해지' END , '' ) WHEN SUBSTR(A.APPL_END_DTTM, 1, 8) = SUBSTR(A.APPL_STRT_DTTM, 1, 8) THEN '당일기변취소' WHEN TO_DATE(SUBSTR(A.APPL_END_DTTM, 1, 8), 'YYYYMMDD') - TO_DATE(SUBSTR(A.APPL_STRT_DTTM, 1, 8), 'YYYYMMDD') <= 14 THEN '14일이내취소' ELSE '일반취소' END AS DVC_CHG_TMNT_RSN_NM , D.SOC_CODE AS DVC_RATE_CD , FN_GET_RATENM(D.SOC_CODE) AS DVC_RATE_NM , E.SOC AS RATE_CD , FN_GET_RATENM(E.SOC) AS RATE_NM , D.MODEL_SALE_POLICY_CODE AS SALE_PLCY_CD , TO_CHAR(NVL(D.ENGG_MNTH_CNT,0)) AS INST_MNTH_CNT , TO_CHAR(NVL(D.MODEL_MONTHLY,0)) AS ENGG_MNTH_CNT , A.MODEL_NM AS DVC_MODEL_NM , A.INTM_SRL_NO AS DVC_INTM_SRL_NO , H.MODEL_NM , H.INTM_SRL_NO , A.AGNT_CD ,FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM , B.OPEN_AGNT_CD , FN_GET_ORGNM(A.AGNT_CD) AS AGNT_NM , NVL(G.INST_ORGIN_AMNT, 0) AS INST_ORGIN_AMNT , D.MODEL_PRICE , G.GRNT_INSR_MNGM_NO , FN_GET_CODENM('MSP0011', G.GRNT_INSR_STAT_CD) AS GRNT_INSR_STAT_NM , (SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = I.FST_RATE_CD) AS FST_RATE_NM FROM MSP_DVC_CHG_AGNT_HST A , MSP_JUO_SUB_INFO B , MSP_REQUEST C , MSP_REQUEST_SALEINFO D , MSP_JUO_FEATURE_INFO E , MSP_JUO_ADD_INFO G , MSP_JUO_MODEL_INFO H , MSP_REQUEST_DTL I WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.REQUEST_KEY = C.REQUEST_KEY AND A.REQUEST_KEY = D.REQUEST_KEY AND B.CONTRACT_NUM = E.CONTRACT_NUM AND B.CONTRACT_NUM = I.CONTRACT_NUM AND E.SERVICE_TYPE = 'P' AND E.APP_END_DATE = ( SELECT MAX(APP_END_DATE) FROM MSP_JUO_FEATURE_INFO WHERE CONTRACT_NUM = B.CONTRACT_NUM AND SERVICE_TYPE = 'P' ) AND A.CONTRACT_NUM = G.CONTRACT_NUM AND A.EVNT_TRTM_NO = G.EVNT_TRTM_NO AND NVL(G.GRNT_INSR_STAT_CD, 'A') = 'A' /* 동일 이벤트번호로 할부/약정 변경된 건 존재 */ AND A.CONTRACT_NUM = H.CONTRACT_NUM AND H.MODEL_TYPE = 'D1' AND H.APP_END_DATE = ( SELECT MAX(APP_END_DATE) FROM MSP_JUO_MODEL_INFO WHERE CONTRACT_NUM = H.CONTRACT_NUM AND MODEL_TYPE = 'D1' )
AND A.APPL_STRT_DTTM BETWEEN #{applDateFrom}||'000000' AND #{applDateTo}||'235959'
AND (A.CONTRACT_NUM = #{searchName} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND B.SUBSCRIBER_NO = #{searchName}
AND B.SUB_STATUS = #{subStatus}
AND A.AGNT_CD = #{cntpntShopId}
AND C.OPER_TYPE = #{operType}
AND C.ON_OFF_TYPE = #{onOffType}
ORDER BY A.APPL_STRT_DTTM DESC

mapper.select:
/* dvcChgMapper.getDvcChgListExcel */
SELECT A.CONTRACT_NUM , B.SUB_STATUS , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS_NM , B.SUBSCRIBER_NO , B.SUBSCRIBER_NO AS SUBSCRIBER_NO_MASK , B.SUB_LINK_NAME AS CSTMR_NAME , SUBSTR(CRYPTO_AES256.DEC_AES(B.USER_SSN), 1, 6) AS BIRTH_DT , FN_GET_CODENM('RCP9001', C.OPER_TYPE) AS OPER_TYPE_NM , FN_GET_CODENM('RCP9004', C.REQ_BUY_TYPE) AS REQ_BUY_TYPE_NM , FN_GET_CODENM('RCP0007', C.ON_OFF_TYPE) AS ON_OFF_TYPE_NM , CASE WHEN SUBSTR(I.SIM_INFO, 36, 1) IN ('A', 'R') THEN ( SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(I.SIM_INFO, 1, 2)) ELSE (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(I.INST_INFO, 1, 2)) END AS SPRT_TP_NM , TO_CHAR(C.REQ_IN_DAY, 'YYYYMMDDHH24MISS') AS REQ_IN_DAY , TO_CHAR(C.REQ_IN_DAY, 'YYYY-MM-DD HH24:MI:SS') AS REQ_IN_DAY_EX , TO_CHAR(TO_DATE(B.LST_COM_ACTV_DATE,'YYYYMMDD'), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE , SUBSTR(A.APPL_STRT_DTTM, 1, 8) AS DVC_CHG_DT , TO_CHAR(TO_DATE(SUBSTR(A.APPL_STRT_DTTM, 1, 8), 'YYYYMMDD'), 'YYYY-MM-DD') AS DVC_CHG_DT_EX , DECODE(A.APPL_END_DTTM, '99991231000000', DECODE(B.SUB_STATUS , 'C' ,SUBSTR(SUB_STATUS_DATE , 0 , 8) , '' ), SUBSTR(A.APPL_END_DTTM, 1, 8)) AS DVC_CHG_TMNT_DT , DECODE(A.APPL_END_DTTM, '99991231000000', DECODE(B.SUB_STATUS , 'C' ,TO_CHAR(TO_DATE(SUBSTR(SUB_STATUS_DATE , 0 , 8) , 'YYYYMMDD') , 'YYYY-MM-DD') , '' ), TO_CHAR(TO_DATE(SUBSTR(A.APPL_END_DTTM, 1, 8), 'YYYYMMDD'), 'YYYY-MM-DD')) AS DVC_CHG_TMNT_DT_EX , CASE WHEN A.APPL_END_DTTM = '99991231000000' THEN DECODE(B.SUB_STATUS , 'C' , CASE WHEN TO_DATE(SUBSTR(B.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD') = 0 THEN '당일기변취소' WHEN TO_DATE(SUBSTR(B.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD') < 15 THEN '14일이내해지' WHEN TO_DATE(SUBSTR(B.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD') < 90 THEN '90일이내해지' ELSE '일반해지' END , '' ) WHEN SUBSTR(A.APPL_END_DTTM, 1, 8) = SUBSTR(A.APPL_STRT_DTTM, 1, 8) THEN '당일기변취소' WHEN TO_DATE(SUBSTR(A.APPL_END_DTTM, 1, 8), 'YYYYMMDD') - TO_DATE(SUBSTR(A.APPL_STRT_DTTM, 1, 8), 'YYYYMMDD') <= 14 THEN '14일이내취소' ELSE '일반취소' END AS DVC_CHG_TMNT_RSN_NM , D.SOC_CODE AS DVC_RATE_CD , FN_GET_RATENM(D.SOC_CODE) AS DVC_RATE_NM , E.SOC AS RATE_CD , FN_GET_RATENM(E.SOC) AS RATE_NM , D.MODEL_SALE_POLICY_CODE AS SALE_PLCY_CD , TO_CHAR(NVL(D.ENGG_MNTH_CNT,0)) AS INST_MNTH_CNT , TO_CHAR(NVL(D.MODEL_MONTHLY,0)) AS ENGG_MNTH_CNT , A.MODEL_NM AS DVC_MODEL_NM , A.INTM_SRL_NO AS DVC_INTM_SRL_NO , H.MODEL_NM , H.INTM_SRL_NO , A.AGNT_CD ,FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM , B.OPEN_AGNT_CD , FN_GET_ORGNM(A.AGNT_CD) AS AGNT_NM , NVL(G.INST_ORGIN_AMNT, 0) AS INST_ORGIN_AMNT , D.MODEL_PRICE , G.GRNT_INSR_MNGM_NO , FN_GET_CODENM('MSP0011', G.GRNT_INSR_STAT_CD) AS GRNT_INSR_STAT_NM , (SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = I.FST_RATE_CD) AS FST_RATE_NM , NVL(G.KD_SUPOT_DSCN_AMNT, 0) AS KD_SUPOT_DSCN_AMNT FROM MSP_DVC_CHG_AGNT_HST A , MSP_JUO_SUB_INFO B , MSP_REQUEST C , MSP_REQUEST_SALEINFO D , MSP_JUO_FEATURE_INFO E , MSP_JUO_ADD_INFO G , MSP_JUO_MODEL_INFO H , MSP_REQUEST_DTL I WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND A.REQUEST_KEY = C.REQUEST_KEY AND A.REQUEST_KEY = D.REQUEST_KEY AND B.CONTRACT_NUM = E.CONTRACT_NUM AND B.CONTRACT_NUM = I.CONTRACT_NUM AND E.SERVICE_TYPE = 'P' AND E.APP_END_DATE = ( SELECT MAX(APP_END_DATE) FROM MSP_JUO_FEATURE_INFO WHERE CONTRACT_NUM = B.CONTRACT_NUM AND SERVICE_TYPE = 'P' ) AND A.CONTRACT_NUM = G.CONTRACT_NUM AND A.EVNT_TRTM_NO = G.EVNT_TRTM_NO AND NVL(G.GRNT_INSR_STAT_CD, 'A') = 'A' /* 동일 이벤트번호로 할부/약정 변경된 건 존재 */ AND A.CONTRACT_NUM = H.CONTRACT_NUM AND H.MODEL_TYPE = 'D1' AND H.APP_END_DATE = ( SELECT MAX(APP_END_DATE) FROM MSP_JUO_MODEL_INFO WHERE CONTRACT_NUM = H.CONTRACT_NUM AND MODEL_TYPE = 'D1' )
AND A.APPL_STRT_DTTM BETWEEN #{applDateFrom}||'000000' AND #{applDateTo}||'235959'
AND (A.CONTRACT_NUM = #{searchName} OR A.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND B.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND B.SUBSCRIBER_NO = #{searchName}
AND B.SUB_STATUS = #{subStatus}
AND A.AGNT_CD = #{cntpntShopId}
AND C.OPER_TYPE = #{operType}
AND C.ON_OFF_TYPE = #{onOffType}
ORDER BY A.APPL_STRT_DTTM DESC
